parameters.jsCode:
const candidates = $json.candidates || [];
const text = candidates?.[0]?.content?.parts?.[0]?.text || '';

let email = {};
try {
  const jsonMatch = text.match(/```json\n?([\s\S]*?)\n?```/);
  if (jsonMatch) {
    email = JSON.parse(jsonMatch[1]);
  } else {
    email = JSON.parse(text);
  }
} catch (e) {
  email = {
    subject: 'Quick question about ' + ($('Parse Prospect Data').first().json.prospect_company || 'your company'),
    body: text,
    personalization_hook: '',
    cta: 'Would you be open to a quick chat?'
  };
}

const prevData = $('Parse Prospect Data').first().json;
return [{
  json: {
    prospect_name: prevData.prospect_name,
    prospect_email: prevData.prospect_email || '',
    prospect_company: prevData.prospect_company,
    subject: email.subject || '',
    body: email.body || '',
    personalization_hook: email.personalization_hook || '',
    cta: email.cta || '',
    word_count: (email.body || '').split(' ').length,
    created_at: new Date().toISOString()
  }
}];
